import functools

def logger(func):
    @functools.wraps(func)
    def wrapper(*args, **kwargs):
        print(f'Calling {func.__name__}')
        result = func(*args, **kwargs)
        print(f'Done: {result}')
        return result
    return wrapper

@logger
def add(a, b):
    return a + b

result = add(5, 3)

